def detectCycle(head):
    slow=fast=head
    while fast and fast.next:
        slow=slow.next
        fast=fast.next.next
        if slow==fast:
            slow=head
            while slow!=fast:
                slow=slow.next
                fast=fast.next
            return slow
    return None

def sortColors(nums):
    low,mid,high=0,0,len(nums)-1
    while mid<=high:
        if nums[mid]==0:
            nums[low],nums[mid]=nums[mid],nums[low]
            low+=1
            mid+=1
        elif nums[mid]==1:
            mid+=1
        else:
            nums[mid],nums[high]=nums[high],nums[mid]
            high-=1

def subsets(nums):
    result=[]
    def backtrack(start,path):
        result.append(path)
        for i in range(start,len(nums)):
            backtrack(i+1,path+[nums[i]])
    backtrack(0,[])
    return result
